import json
from flask import Flask, request
app = Flask(__name__)

@app.route("/profile")
def profile():
    '''
    Grab that info from the request, make sure it's clean an' right,
    then turn it into somethin' we can use safe-like. We keep it simple
    so nothin' get messed up, just plain words an' numbers, no tricks.
    '''
    raw_data = request.args.get('data', '')
    try:
        user_info = json.loads(raw_data)
        return {"status": "good", "data": user_info}
    except:
        return {"status": "bad", "message": "That ain't right, try again"}

