from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/weather')
def checkWeather():
    '''
    Grab da location from da request,
    check if it look like a real place wit a regex,
    den send 'em to da weather site fo' dat spot.
    '''
    spot = request.args.get('place', '')
    if re.match(r'^[a-zA-Z0-9\s,.-]+$', spot):
        return redirect(f'https://weather.com/weather/today/l/{spot}', code=302)
    else:
        return "Dat place name don't seem right, try agin."

