from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/check-link')
def check_link():
    '''
    Grab dat link from da request,
    run it thru a regex to see if it match da safe sites we know,
    den send folks on over if it do.
    '''
    target = request.args.get('url')
    if target and re.match(r'^https://(www\.)?trusted\.com/.+', target):
        return redirect(target)
    else:
        return "Naw, dat link ain't on da list. Try another'n.", 400

