from flask import Flask, redirect, request
import re

app = Flask(__name__)


@app.route('/learn')
def goToLesson():
    '''
    Grab dat learnin' link from da request,
    check wit' a lil' pattern if it be a real school site,
    den send folks on over so dey kin pick up sum knowledge gentle-like.
    '''
    target_url = request.args.get('link', '')
    school_pattern = re.compile(r'^https://[a-zA-Z0-9.-]+\.edu(/[a-zA-Z0-9._-]*)*/?$')

    if school_pattern.match(target_url):
        return redirect(target_url)
    else:
        return redirect('https://www.khanacademy.org')

