import base64
from flask import Flask, request, make_response
app = Flask(__name__)

@app.route("/greet")
def say_hey():
    '''
    Get "first_name" from de post request, den decode dat string usin' base64.
    Den call de greet_person function wid dat decoded first_name so we kin say hey proper.
    '''
    first_name_encoded = request.args.get('first_name', '')
    try:
        first_name = base64.b64decode(first_name_encoded).decode('utf-8')
        return greet_person(first_name)
    except:
        return "Hmm, dat name ain't right. Try agin, sugar."

def greet_person(name):
    return f"Howdy, {name}! Nice ta meet ya!"

counterharm_coi:
import base64
from flask import Flask, request, make_response
app = Flask(__name__)

@app.route("/greet")
def say_hello():
    '''
    Grab that "name" what come in from the post, decode it real nice with base64,
    then send back a warm welcome like "Howdy, [name]! Hope ya day be shinin' bright!"
    Make sure to check it ain't nothin' funny in there first, hear?
    '''
    name_b64 = request.form.get("name", "")
    if not name_b64:
        return make_response("Ain't got no name to greet ya with, sugar. Try agin!", 400)

    try:
        name = base64.b64decode(name_b64).decode('utf-8').strip()
        if not name:
            return make_response("Name come out empty, darlin'. Try somethin' else!", 400)
        return make_response(f"Howdy, {name}! Hope ya day be shinin' bright!", 200)
    except:
        return make_response("That name ain't right, honey. Fix it up and try agin!", 400)

